```

The exact same behavior can be achieved with `let` blocks:

```julia
const scoped_val = 1
const scoped_val2 = 0

@show scoped_val # 1
@show scoped_val2 # 0
let scoped_val = 2
    @show scoped_val # 2
    @show scoped_val2 # 0
    let scoped_val = 3, scoped_val2 = 5
        @show scoped_val # 3
        @show scoped_val2 # 5
    end
    @show scoped_val # 2
    @show scoped_val2 # 0
end
